const evento = $json.body?.evento ?? $json.evento;
const tenantId = $json.body?.tenant_id ?? $json.tenant_id;
const d = ($json.body?.dados ?? $json.dados) || {};

const hora = (h) => (h ? String(h).slice(0, 5) : '');

const templates = {
  confirmacao: `Olá ${d.cliente_nome}! Sua montagem (${d.produto_nome || 'seu móvel'}) está agendada para ${d.data_agendada} às ${hora(d.hora_agendada)}. Responda SIM para confirmar. Acompanhe: ${d.link_portal}`,
  lembrete: `Olá ${d.cliente_nome}! Lembrete: amanhã (${d.data_agendada}) teremos um montador na sua casa às ${hora(d.hora_agendada)}. Confirma? ${d.link_portal}`,
  em_rota: `Oi ${d.cliente_nome}! ${d.montador_nome || 'Seu montador'} está a caminho. Acompanhe em tempo real: ${d.link_portal}`,
  nps: `Olá ${d.cliente_nome}! Como foi sua experiência com a montagem do(a) ${d.produto_nome || 'seu móvel'}? Avalie de 0 a 10: ${d.link_portal}`,
  assistencia: `${d.cliente_nome}, identificamos um problema na sua montagem${d.motivo_assist ? ' (' + d.motivo_assist + ')' : ''}. Nossa equipe vai entrar em contato. Acompanhe: ${d.link_portal}`,
  reagendamento: `${d.cliente_nome}, seu agendamento foi remarcado para ${d.data_agendada} às ${hora(d.hora_agendada)}. Confira: ${d.link_portal}`,
};

return {
  json: {
    telefone: d.cliente_whatsapp,
    mensagem: templates[evento] || null,
    tipo: evento,
    os_id: d.os_id,
    tenant_id: tenantId,
    comunicacao_id: d.comunicacao_id,
  },
};
